  2873 => [ // SD 価格設定と条件技術
    ['icon' => '💡', 'title' => '条件技術とは', 'body' => 'SAPの条件技術は、価格設定だけでなく様々な業務ルールを管理する汎用的なフレームワークです。条件テーブル、条件タイプ、アクセス順序の3層構造で構成され、価格決定のロジックを柔軟に定義できます。'],
    ['icon' => '📋', 'title' => '条件テーブルの構造', 'body' => '条件テーブルは、価格決定のキー項目を組み合わせたものです。例えば「販売組織＋得意先＋品目」の組み合わせで価格を決定します。キー項目数は3〜5項目が一般的です。'],
    ['icon' => '🔢', 'title' => '価格決定手順', 'body' => '価格決定手順（Procedure）は、複数の条件タイプを順序付けて実行するフレームワークです。ステップ順に条件が計算され、小計や累計を挟みながら最終価格が算出されます。'],
    ['icon' => '📊', 'title' => '代表的な条件タイプ', 'body' => 'PR00（価格）、KA（数量割引）、K004（得意先割引一括）、K005（得意先固有価格）、MWST（消費税）、FR1（運送料）など。条件タイプごとに計算ルールと更新方法が定義されています。'],
    ['icon' => '🎯', 'title' => '価格決定の優先順位', 'body' => '同一の条件に対して複数のマスタレコードがある場合、アクセス順序に従って最も具体的な条件が優先されます。得意先別価格 > 価格表 > 基本価格 の順で優先度が高くなります。'],
    ['icon' => '🔍', 'title' => '条件マスタの照会と保守', 'body' => 'VK11で条件マスタを作成・変更、VK13で照会します。条件のコピー（VK31）や一括保守も可能で、プロモーション時の価格変更を効率的に行えます。'],
    ['icon' => '💡', 'title' => '条件タイプのカスタマイズ', 'body' => '新しい条件タイプを作成する際は、計算ルール（数量単価、％、絶対値等）、更新方法（A：自動、B：自動＋手動）、有効性などを定義します。新規条件タイプの作成はIMGの条件定義で行います。'],
    ['icon' => '⚡', 'title' => 'プロモーション価格管理', 'body' => '期間限定のプロモーション価格は、条件マスタの有効期間を設定することで簡単に実現できます。開始日と終了日を指定し、バッチジョブで自動的に有効/無効を切り替えられます。'],
  ],

  2874 => [ // 出荷と輸送
    ['icon' => '🚚', 'title' => '出荷プロセスの全体像', 'body' => '出荷プロセス：出荷伝票作成（VL01N）→ ピッキング → 出庫転記 → 配送ルート決定 → 出荷完了確認。各段階で在庫と会計のデータが更新され、顧客への納品が追跡されます。'],
    ['icon' => '📋', 'title' => '出荷伝票の種類', 'body' => 'LF＝標準出荷、LR＝返品出荷、NL＝無償出荷。出荷タイプごとに制御パラメータ（ピッキング要否、出庫転記の自動/手動、配送要件）が異なります。'],
    ['icon' => '🔍', 'title' => 'ピッキングと在庫引当', 'body' => '出荷伝票作成時、在庫引当が自動的に行われます。ピッキングはバッチ単位、分割納入可能で、倉庫管理システム（WM/EWM）と連携することも可能です。'],
    ['icon' => '📦', 'title' => '出庫転記の意味', 'body' => '出庫転記により在庫が削減され、同時に売上原価が自動計上されます。勘定は品目の評価クラスと勘定決定キーで自動的に決まり、在庫と会計の整合性が保たれます。'],
    ['icon' => '🛣️', 'title' => '輸送ルート管理', 'body' => 'VT01/VT02で輸送ルートと運送業者を管理します。ルート決定は品目や納入先に基づいて自動的に行われ、輸送コストの見積もりや追跡が可能です。'],
    ['icon' => '📊', 'title' => '出荷関連レポート', 'body' => 'VL06F（出庫一覧）、V_LIKP（出荷伝票照会）、VT11（輸送コスト計算）などで出荷状況を把握できます。FioriのOutbound Delivery Monitorでリアルタイムな進捗確認も可能です。'],
    ['icon' => '⚠️', 'title' => '出荷処理の注意点', 'body' => '出庫転記は取消が可能ですが、適切な手順（VL09）で行う必要があります。また、出荷完了後の納入指示変更は伝票フローに影響するため、十分な確認が必要です。'],
    ['icon' => '💡', 'title' => '出荷リードタイムの短縮', 'body' => '出荷リードタイム短縮には、ピッキングルートの最適化、バーコード/RFIDの活用、EWM（Extended Warehouse Management）との連携が効果的です。'],
  ],

  2875 => [ // MM/SD 連携実務
    ['icon' => '🔄', 'title' => 'MM-SD連携の全体像', 'body' => 'MM（購買/在庫）とSD（販売/出荷）は、在庫管理と品目マスタを介して密接に連携しています。SDの出庫転記はMMの在庫を減少させ、MMの入庫は在庫を増加させ、同じ在庫データを共有します。'],
    ['icon' => '📦', 'title' => '在庫の共通管理', 'body' => '品目マスタのプラントデータはMMとSDで共通です。SDが販売可能な在庫数量はMMの在庫管理に基づいており、購買計画も販売実績に基づいて策定されます。'],
    ['icon' => '📋', 'title' => '受注連携購買', 'body' => '受注に対して在庫がない場合、自動的に購買依頼を生成する「受注連携購買」の設定が可能です。これにより、受注から購買までをシームレスに連携できます。'],
    ['icon' => '🏭', 'title' => 'Production Orderの連携', 'body' => '受注在庫が不足している場合、生産計画（PP）と連携して製造指示を出すことも可能です。Make-to-Order（MTO）のシナリオでは、SD受注→PP生産→MM購買と自動連携します。'],
    ['icon' => '📊', 'title' => '在庫引当の仕組み', 'body' => '受注作成時に在庫引当が行われます。引当可能数量は現在の在庫数量から既に引当済みの数量を差し引いた数量です。ATP（Available-to-Promise）ロジックが納期回答を自動計算します。'],
    ['icon' => '🚚', 'title' => '出荷と入荷の調整', 'body' => 'SDの出荷スケジュールとMMの入荷スケジュールを調整することで、在庫を最適化できます。SAP IBP（Integrated Business Planning）を使えば、需要と供給のバランスをさらに高度に計画できます。'],
    ['icon' => '💰', 'title' => '原価フローの連携', 'body' => 'MMの購買価格が製品原価に影響し、SDの販売価格が売上と利益を決定します。COで原価と収益を統合分析することで、製品ごとの収益性を正確に把握できます。'],
    ['icon' => '💡', 'title' => 'CRMとSAPの連携', 'body' => 'SDとMMの円滑な連携には、CRM（顧客管理）データの品質も重要です。SAP Sales CloudやC4Cとの連携により、見積から受注、そして調達までの一貫したプロセスが実現できます。'],
    ['icon' => '✅', 'title' => 'MM/SD連携のベストプラクティス', 'body' => '✓ 品目マスタのプラントデータはMMとSDで共有 ✓ 受注時には在庫引当が自動実行 ✓ 在庫不足時は受注連携購買で自動補充 ✓ ATPチェックで正確な納期回答'],
    ['icon' => '📈', 'title' => '連携のKPI管理', 'body' => '在庫充足率（Fill Rate）、受注から出荷までのリードタイム、在庫回転率など、MM/SD連携の効果を測るKPIを定期的にモニタリングしましょう。SAPのアナリティクス機能で可視化できます。'],
  ],

  // ======== S/4HANA 移行プロフェッショナルパス (steps: 2877,2878,2879,2880,2881) ========

  2877 => [ // アーキテクチャ理解
    ['icon' => '🏗️', 'title' => 'S/4HANAのアーキテクチャ', 'body' => 'S/4HANAは、従来のECCからアーキテクチャが大きく変わりました。インメモリデータベースHANA上で動作し、テーブル構造が大幅に簡素化されています。Fioriが標準のUIフレームワークとなりました。'],
    ['icon' => '💾', 'title' => 'HANAデータベースの特徴', 'body' => 'HANAは行指向と列指向の両方をサポートするハイブリッドDBです。圧縮率が高く、集計処理が高速です。S/4HANAでは従来のインデックスや集計テーブルが不要になり、データモデルがシンプルになりました。'],
    ['icon' => '📋', 'title' => 'Simplification List', 'body' => 'SAPが公開するSimplification Listには、ECCからS/4HANAへの移行で影響を受ける全機能が記載されています。廃止されたトランザクションコード、削除されたテーブル、変更されたプロセスを事前に確認することが必須です。'],
    ['icon' => '🎨', 'title' => 'Fiori UXの標準化', 'body' => 'S/4HANAではFioriが標準UIとなり、SAP GUIは特定のカスタマイジング作業に限定されつつあります。Fiori Launchpadをシングルアクセスポイントとして、全ての業務をWebブラウザから実行できます。'],
    ['icon' => '☁️', 'title' => 'デプロイオプション', 'body' => 'S/4HANAは3つのデプロイオプションがあります：On-Premise（自社管理）、Cloud Private Edition（シングルテナント）、Cloud Public Edition（マルチテナント）。ビジネス要件に合わせて選択します。'],
    ['icon' => '🔄', 'title' => 'Embedded Analytics', 'body' => 'S/4HANAは組み込み分析機能（Embedded Analytics）を標準装備しています。CDS Viewベースのレポートで、ETLツールなしでリアルタイム分析が可能です。SAP Fiori分析アプリから直接アクセスできます。'],
    ['icon' => '🔒', 'title' => 'セキュリティモデル', 'body' => 'S/4HANAではFioriベースの権限モデルが標準です。PFCGロールにFioriカタログを割り当て、タイルレベルのアクセス制御を行います。また、CDS ViewのDCLでデータレベル権限も細かく制御できます。'],
    ['icon' => '💡', 'title' => 'BTPとの統合', 'body' => 'S/4HANAはSAP BTP（Business Technology Platform）とシームレスに統合されます。拡張開発、インテグレーション、アナリティクス、AIの各サービスをクラウドネイティブに活用できます。'],
    ['icon' => '🚀', 'title' => 'Clean Core戦略', 'body' => 'SAPが推進するClean Core戦略は、S/4HANAのコアをクリーンに保ち、拡張はBTPやSide-by-Sideで実装するアプローチです。標準機能のアップグレードを容易にし、TCOを削減します。'],
  ],

  2878 => [ // 移行方式の選定
    ['icon' => '🔄', 'title' => 'Brownfield（システムコンバージョン）', 'body' => '既存のECCシステムをそのままS/4HANAにアップグレードする方式です。アドオンやカスタマイズを引き継げるため、移行期間が短く、コストも抑えられます。ただし、Simplification Listの影響を受けるアドオンの修正が必要です。'],
    ['icon' => '🌱', 'title' => 'Greenfield（新規導入）', 'body' => '既存システムを捨てて、新たにS/4HANAを構築する方式です。ビジネスプロセスをゼロから見直す機会であり、Clean Coreを最初から実現できます。ただし、移行期間が長く、コストも高くなります。'],
    ['icon' => '🔍', 'title' => 'Readiness Check 2.0', 'body' => 'SAP Readiness Checkは、S/4HANA移行の準備状態を評価するツールです。システムの互換性、アドオンの影響、データボリューム、推奨アクションを自動分析します（Fioriアプリで利用可能）。'],
    ['icon' => '📋', 'title' => 'Custom Code Migration', 'body' => 'アドオンやカスタムコードのS/4HANA対応状況を分析するプロセスです。ABAP Test Cockpit（ATC）を使って非推奨構文やSimplification Listの影響をチェックし、修正計画を立てます。'],
    ['icon' => '💰', 'title' => 'TCO分析とROI試算', 'body' => '移行方式の選定には、総所有コスト（TCO）と投資対効果（ROI）の分析が不可欠です。ライセンス費用、インフラコスト、移行作業工数、運用コストを比較し、最適な方式を選びましょう。'],
    ['icon' => '📅', 'title' => '移行スケジュール設計', 'body' => 'Brownfieldで6〜12ヶ月、Greenfieldで12〜24ヶ月が一般的な移行期間です。SAP Activate Methodologyのフェーズ（Discover/Prepare/Explore/Realize/Deploy/Run）に沿って計画を策定します。'],
    ['icon' => '🏢', 'title' => '組織体制の準備', 'body' => '移行プロジェクトには、ビジネス側のキーユーザー、IT部門、SAPコンサルタント、プロジェクトマネージャーの参画が必須です。また、チェンジマネジメントチームの設置も推奨されます。'],
    ['icon' => '⚡', 'title' => 'ハイブリッドアプローチ', 'body' => '一部のモジュールだけ先に移行する「段階的移行」や、特定のプロセスだけGreenfieldで再構築する「セレクティブ移行」も選択肢です。SAPのSelective Data Transitionで実現できます。'],
    ['icon' => '✅', 'title' => '方式選定の判断ポイント', 'body' => '✓ 既存アドオンの量と複雑度 ✓ カスタマイズの肥大化度 ✓ 予算と期間の制約 ✓ ビジネスプロセス変革の必要性 ✓ 組織の変革受容性。これらを総合的に評価して判断します。'],
  ],

  2879 => [ // システム移行の実務
    ['icon' => '🛠️', 'title' => 'SUMとSoftware Update Manager', 'body' => 'SUM（Software Update Manager）は、S/4HANA移行の主要ツールです。ダウンタイム最小化オプション（near-zero downtime）も提供され、システム移行中の業務影響を最小限に抑えられます。'],
    ['icon' => '📂', 'title' => 'SAP Migration Cockpit', 'body' => 'SAP Migration Cockpitは、マスタデータとトランザクションデータの移行ツールです。テンプレートに沿ってデータを準備し、アップロードから検証までをガイド付きで実行できます。'],
    ['icon' => '🔄', 'title' => 'データ移行の戦略', 'body' => '全データ移行 vs 必要データのみ移行の判断が必要です。オープンアイテム、マスタデータ、コンフィグレーションは最小限移行し、履歴データはアーカイブして別途参照可能にする戦略が一般的です。'],
    ['icon' => '📋', 'title' => 'アドオン管理と修正', 'body' => 'S/4HANA移行では、アドオンのS/4HANA対応確認と不適合アドオンの修正が最大の工数要因です。SAPが出すアドオン互換性レポートを活用し、計画的に対処しましょう。'],
    ['icon' => '🧪', 'title' => 'テスト戦略', 'body' => '単体テスト、結合テスト、ユーザー受入テスト（UAT）、パフォーマンステスト、レグレッションテストの5段階のテストが推奨されます。SAP Test Automation Toolkitでテストを効率化できます。'],
    ['icon' => '📅', 'title' => 'カットオーバー計画', 'body' => '本番切替（カットオーバー）は、週末や長期休暇を利用して計画します。データ最終同期、システム停止、コンバージョン実行、動作確認、業務再開の時間軸を詳細に設定します。'],
    ['icon' => '🔄', 'title' => 'ロールバック計画', 'body' => 'カットオーバーが失敗した場合のロールバック計画も事前に策定します。ECCへの復旧手順、データ整合性の確認方法、業務継続計画（BCP）を含めた包括的な対応が必要です。'],
    ['icon' => '💡', 'title' => '移行後の性能検証', 'body' => 'S/4HANA移行後は、パフォーマンスのベースライン測定とチューニングが重要です。移行前後の応答時間、バッチ処理時間、DBアクセス時間を比較し、必要に応じてHANA固有の最適化を実施します。'],
    ['icon' => '📚', 'title' => '移行後サポート体制', 'body' => 'カットオーバー後は、一定期間のハイパーケア期間を設け、ユーザーからの問い合わせに迅速に対応できる体制を整えます。また、SAP Standard SupportまたはEnterprise Supportの契約も確認しましょう。'],
  ],

  2880 => [ // テスト計画と実行
    ['icon' => '📋', 'title' => 'テスト戦略の策定', 'body' => 'SAPプロジェクトにおけるテスト戦略では、テスト範囲、テストレベル（単体/結合/受け入れ）、テストデータ、テストツール、役割分担を明確に定義します。Vモデルに沿ったテスト計画が一般的です。'],
    ['icon' => '🧪', 'title' => '単体テスト（Unit Test）', 'body' => '開発したプログラムや設定が単独で正しく動作するかを検証します。ABAP Unit（開発者テスト）、カスタマイジングの設定確認、レポートの出力検証などが含まれます。'],
    ['icon' => '🔗', 'title' => '結合テスト（Integration Test）', 'body' => '複数のモジュールやシステムを連携させたテストです。FIとCOの連携、MMとSDの在庫連携、FI-AAとFI-GLの連携など、クロスモジュールのシナリオを中心にテストします。'],
    ['icon' => '📝', 'title' => 'ユーザー受入テスト（UAT）', 'body' => '実際のユーザーが自分の業務シナリオに沿ってシステムをテストします。テストシナリオは現場の業務プロセスをベースに作成し、合格基準を事前に明確にします。'],
    ['icon' => '📊', 'title' => 'テスト管理と進捗管理', 'body' => 'テストケースの作成、テスト実行、結果記録、障害管理は、Excelやテスト管理ツール（SAP Solution Manager Test Suite、HP ALM等）で一元管理します。テスト進捗は週次で報告します。'],
    ['icon' => '💡', 'title' => 'Regression Testの自動化', 'body' => 'SAPのRegression Testは、SAP CBTA（Component Based Test Automation）、Tricentis Tosca、Worksoftなどで自動化できます。バグ修正やアドオン更新のたびに全テストを手動実行するのは非現実的です。'],
    ['icon' => '🔍', 'title' => 'バグ管理とトリアージ', 'body' => 'テストで発見されたバグは、重要度（Critical/Major/Minor）と優先度（High/Medium/Low）で分類し、修正と再テストのサイクルを管理します。SAP Solution ManagerのIssue Management機能が使えます。'],
    ['icon' => '📈', 'title' => 'テスト完了基準', 'body' => 'テスト完了の判断基準：全テストケースの実行完了、Critical/Majorバグの全件修正と再テスト完了、ユーザー受入テストの合格率95%以上、パフォーマンス基準の達成。'],
    ['icon' => '✅', 'title' => 'テストフェーズのポイント', 'body' => 'テストデータは本番に近いほど効果的です。また、テストシナリオは「正常系」だけでなく「異常系」「エラー系」も十分にカバーしましょう。テスト工程の工数は全プロジェクト工数の30〜40%が目安です。'],
