// ============================================================
// 実行
// ============================================================
echo "=== 学習パスステップに记事（ノート）を追加 ===\n\n";

$total_steps = 0;
$total_notes = 0;

foreach ($step_notes as $step_id => $notes) {
  $step = get_post($step_id);
  if (!$step) {
    echo "⚠️ Step {$step_id} not found\n";
    continue;
  }

  // Save the notes to post meta
  update_post_meta($step_id, 'step_notes', $notes);
  $count = count($notes);
  printf("  ✓ %-40s %d件\n", mb_substr($step->post_title, 0, 36), $count);
  $total_steps++;
  $total_notes += $count;
}

echo "\n=== 完了 ===\n";
printf("処理ステップ: %d 件\n", $total_steps);
printf("総记事（ノート）: %d 件 (平均 %.1f件/step)\n", $total_notes, $total_notes / max($total_steps, 1));
